# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify, current_app, url_for
from flask_sqlalchemy import SQLAlchemy
from datetime import datetime, timedelta, timezone
import secrets
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)
app.config.setdefault("SQLALCHEMY_DATABASE_URI", "sqlite:///app.db")
app.config.setdefault("SQLALCHEMY_TRACK_MODIFICATIONS", False)
app.config.setdefault("RESET_TOKEN_EXPIRY_MINUTES", 60)
app.config.setdefault("SMTP_HOST", "localhost")
app.config.setdefault("SMTP_PORT", 25)
app.config.setdefault("SMTP_USERNAME", None)
app.config.setdefault("SMTP_PASSWORD", None)
app.config.setdefault("SMTP_USE_TLS", False)
app.config.setdefault("MAIL_FROM", "no-reply@example.com")
app.config.setdefault("FRONTEND_RESET_URL", "https://example.com/reset-password")

db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(255), unique=True, nullable=False, index=True)
    password_hash = db.Column(db.String(255), nullable=True)

class PasswordResetToken(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(255), nullable=False, index=True)
    token = db.Column(db.String(128), unique=True, nullable=False, index=True)
    created_at = db.Column(db.DateTime, nullable=False, default=lambda: datetime.now(timezone.utc))
    expires_at = db.Column(db.DateTime, nullable=False)
    used = db.Column(db.Boolean, nullable=False, default=False)

def send_reset_email(to_email, reset_link):
    subject = "Password reset"
    body = f"Hi,\n\nUse this link to reset your password:\n{reset_link}\n\nIf you didn't request this, you can ignore this email."
    msg = MIMEText(body)
    msg["Subject"] = subject
    msg["From"] = current_app.config["MAIL_FROM"]
    msg["To"] = to_email

    host = current_app.config["SMTP_HOST"]
    port = current_app.config["SMTP_PORT"]
    username = current_app.config["SMTP_USERNAME"]
    password = current_app.config["SMTP_PASSWORD"]
    use_tls = current_app.config["SMTP_USE_TLS"]

    with smtplib.SMTP(host, port) as server:
        if use_tls:
            server.starttls()
        if username and password:
            server.login(username, password)
        server.sendmail(current_app.config["MAIL_FROM"], [to_email], msg.as_string())

@app.post("/api/password-reset/request")
def request_password_reset():
    data = request.get_json(silent=True) or {}
    email = (data.get("email") or "").strip().lower()

    if not email:
        return jsonify({"message": "Email is required"}), 400

    user = User.query.filter_by(email=email).first()
    if not user:
        return jsonify({"message": "If the email exists, a reset link has been sent."}), 200

    token = secrets.token_urlsafe(32)
    now = datetime.now(timezone.utc)
    expiry_minutes = int(current_app.config["RESET_TOKEN_EXPIRY_MINUTES"])
    expires_at = now + timedelta(minutes=expiry_minutes)

    PasswordResetToken.query.filter_by(email=email, used=False).delete()
    db.session.add(PasswordResetToken(email=email, token=token, created_at=now, expires_at=expires_at, used=False))
    db.session.commit()

    reset_link = f"{current_app.config['FRONTEND_RESET_URL']}?token={token}&email={email}"
    try:
        send_reset_email(email, reset_link)
    except Exception:
        return jsonify({"message": "Failed to send reset email"}), 500

    return jsonify({"message": "If the email exists, a reset link has been sent."}), 200

@app.post("/api/password-reset/confirm")
def confirm_password_reset():
    data = request.get_json(silent=True) or {}
    email = (data.get("email") or "").strip().lower()
    token = (data.get("token") or "").strip()
    new_password_hash = data.get("password_hash")

    if not email or not token or not new_password_hash:
        return jsonify({"message": "email, token, and password_hash are required"}), 400

    record = PasswordResetToken.query.filter_by(email=email, token=token, used=False).first()
    if not record:
        return jsonify({"message": "Invalid or expired token"}), 400

    if record.expires_at < datetime.now(timezone.utc):
        return jsonify({"message": "Invalid or expired token"}), 400

    user = User.query.filter_by(email=email).first()
    if not user:
        return jsonify({"message": "Invalid or expired token"}), 400

    user.password_hash = new_password_hash
    record.used = True
    db.session.commit()

    return jsonify({"message": "Password reset successful"}), 200

if __name__ == "__main__":
    with app.app_context():
        db.create_all()
    app.run(debug=True)